import type { HTMLAttributes, KeyboardEvent, MouseEvent } from "react";
import { useDropdownContext } from "./dropdown-context";

type DropdownItemProps = HTMLAttributes<HTMLDivElement>;

export function DropdownItem(props: DropdownItemProps) {
    const { setOpen, triggerRef } = useDropdownContext();

    const handleKeyDown = (e: KeyboardEvent<HTMLDivElement>) => {
        if (e.key === "Enter" || e.key === " ") {
            e.preventDefault();
            props.onClick?.(e as any);
            setOpen(false);
            triggerRef.current?.focus();
        }
        props.onKeyDown?.(e);
    };

    const handleClick = (e: MouseEvent<HTMLDivElement>) => {
        props.onClick?.(e);
        setOpen(false);
        triggerRef.current?.focus();
    };

    return (
        <div
            {...props}
            role="menuitem"
            tabIndex={-1}
            onClick={handleClick}
            onKeyDown={handleKeyDown}
            style={{
                cursor: "pointer",
                padding: "8px 12px",
                outline: "none",
                ...props.style,
            }}
            onMouseEnter={(e) => {
                (e.target as HTMLElement).focus();
                props.onMouseEnter?.(e);
            }}
        />
    );
}

import * as React from "react";
import { useTabsContext } from "./use-tabs";

export interface TabsListProps extends React.HTMLAttributes<HTMLDivElement> { }

export const TabsList = React.forwardRef<HTMLDivElement, TabsListProps>(
    ({ children, onKeyDown, ...props }, ref) => {
        const { orientation, triggers, activationMode, onValueChange } = useTabsContext();

        const handleKeyDown = React.useCallback(
            (event: React.KeyboardEvent<HTMLDivElement>) => {
                const focusedElement = document.activeElement as HTMLButtonElement | null;
                if (!focusedElement) return;

                const currentIndex = triggers.findIndex((t) => t.current === focusedElement);
                if (currentIndex === -1) return;

                let nextIndex = currentIndex;
                const isHorizontal = orientation === "horizontal";

                switch (event.key) {
                    case isHorizontal ? "ArrowRight" : "ArrowDown":
                        nextIndex = (currentIndex + 1) % triggers.length;
                        break;
                    case isHorizontal ? "ArrowLeft" : "ArrowUp":
                        nextIndex = (currentIndex - 1 + triggers.length) % triggers.length;
                        break;
                    case "Home":
                        nextIndex = 0;
                        break;
                    case "End":
                        nextIndex = triggers.length - 1;
                        break;
                    default:
                        onKeyDown?.(event);
                        return;
                }

                event.preventDefault();

                const nextTrigger = triggers[nextIndex]?.current;
                if (nextTrigger) {
                    nextTrigger.focus();
                    if (activationMode === "automatic") {
                        const val = nextTrigger.dataset.value;
                        if (val !== undefined) {
                            onValueChange(val);
                        }
                    }
                }

                onKeyDown?.(event);
            },
            [triggers, orientation, activationMode, onValueChange, onKeyDown]
        );

        return (
            <div
                ref={ref}
                role="tablist"
                aria-orientation={orientation}
                onKeyDown={handleKeyDown}
                {...props}
            >
                {children}
            </div>
        );
    }
);

TabsList.displayName = "Tabs.List";

import type { Meta, StoryObj } from "@storybook/react";
import { Dropdown } from "../../components/dropdown/dropdown";
import { useState } from "react";

const meta = {
    title: "Components/Dropdown",
    component: Dropdown,
    parameters: {
        layout: "centered",
    },
    tags: ["autodocs"],
} satisfies Meta<typeof Dropdown>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Uncontrolled: Story = {
    args: { children: null },
    render: () => (
        <div style={{ minHeight: "300px" }}>
            <Dropdown>
                <Dropdown.Trigger style={{ padding: "8px 16px", cursor: "pointer" }}>
                    Options
                </Dropdown.Trigger>
                <Dropdown.Content>
                    <Dropdown.Item onClick={() => console.log("Account clicked")}>
                        Account
                    </Dropdown.Item>
                    <Dropdown.Item onClick={() => console.log("Settings clicked")}>
                        Settings
                    </Dropdown.Item>
                    <Dropdown.Item onClick={() => console.log("Logout clicked")}>
                        Logout
                    </Dropdown.Item>
                </Dropdown.Content>
            </Dropdown>
        </div>
    ),
};

export const Controlled: Story = {
    args: { children: null },
    render: () => {
        const [open, setOpen] = useState(false);

        return (
            <div style={{ minHeight: "300px" }}>
                <p style={{ marginBottom: "16px" }}>State: {open ? "Open" : "Closed"}</p>
                <Dropdown open={open} onOpenChange={setOpen}>
                    <Dropdown.Trigger style={{ padding: "8px 16px", cursor: "pointer" }}>
                        More Actions
                    </Dropdown.Trigger>
                    <Dropdown.Content>
                        <Dropdown.Item>Edit</Dropdown.Item>
                        <Dropdown.Item>Duplicate</Dropdown.Item>
                        <Dropdown.Item>Delete</Dropdown.Item>
                    </Dropdown.Content>
                </Dropdown>
            </div>
        );
    },
};

import * as React from "react";
import type { Meta, StoryObj } from "@storybook/react";
import { Tabs } from "../../components/tabs/tabs";

const meta = {
    title: "Components/Tabs",
    component: Tabs,
    parameters: {
        layout: "centered",
    },
    tags: ["autodocs"],
} satisfies Meta<typeof Tabs>;

export default meta;
type Story = StoryObj<typeof meta>;

export const BasicTabs: Story = {
    render: () => (
        <Tabs defaultValue="account" style={{ width: 400, fontFamily: "sans-serif" }}>
            <Tabs.List style={{ display: "flex", borderBottom: "1px solid #ccc", gap: 10, paddingBottom: 10 }}>
                <Tabs.Trigger
                    value="account"
                    style={{ padding: "8px 16px", cursor: "pointer", border: "none", background: "transparent" }}
                >
                    Account
                </Tabs.Trigger>
                <Tabs.Trigger
                    value="password"
                    style={{ padding: "8px 16px", cursor: "pointer", border: "none", background: "transparent" }}
                >
                    Password
                </Tabs.Trigger>
                <Tabs.Trigger
                    value="settings"
                    style={{ padding: "8px 16px", cursor: "pointer", border: "none", background: "transparent" }}
                >
                    Settings
                </Tabs.Trigger>
            </Tabs.List>
            <div style={{ padding: "20px 0" }}>
                <Tabs.Content value="account">Make changes to your account here.</Tabs.Content>
                <Tabs.Content value="password">Change your password here.</Tabs.Content>
                <Tabs.Content value="settings">Manage your settings here.</Tabs.Content>
            </div>
        </Tabs>
    ),
};

export const ControlledTabs: Story = {
    render: () => {
        const [tab, setTab] = React.useState("password");
        return (
            <div style={{ width: 400, fontFamily: "sans-serif" }}>
                <div style={{ marginBottom: 20 }}>
                    <button onClick={() => setTab("account")}>Force Account</button>
                    <span style={{ marginLeft: 10 }}>Current: {tab}</span>
                </div>
                <Tabs value={tab} onValueChange={setTab}>
                    <Tabs.List style={{ display: "flex", borderBottom: "1px solid #ccc", gap: 10, paddingBottom: 10 }}>
                        <Tabs.Trigger
                            value="account"
                            style={{ padding: "8px 16px", cursor: "pointer", border: "none", background: "transparent" }}
                        >
                            Account
                        </Tabs.Trigger>
                        <Tabs.Trigger
                            value="password"
                            style={{ padding: "8px 16px", cursor: "pointer", border: "none", background: "transparent" }}
                        >
                            Password
                        </Tabs.Trigger>
                    </Tabs.List>
                    <div style={{ padding: "20px 0" }}>
                        <Tabs.Content value="account">Account settings panel</Tabs.Content>
                        <Tabs.Content value="password">Password settings panel</Tabs.Content>
                    </div>
                </Tabs>
            </div>
        );
    },
};

export const VerticalTabs: Story = {
    render: () => (
        <Tabs defaultValue="tab1" orientation="vertical" style={{ display: "flex", width: 400, gap: 20, fontFamily: "sans-serif" }}>
            <Tabs.List style={{ display: "flex", flexDirection: "column", borderRight: "1px solid #ccc", gap: 10, paddingRight: 10 }}>
                <Tabs.Trigger
                    value="tab1"
                    style={{ padding: "8px 16px", textAlign: "left", cursor: "pointer", border: "none", background: "transparent" }}
                >
                    First Tab
                </Tabs.Trigger>
                <Tabs.Trigger
                    value="tab2"
                    style={{ padding: "8px 16px", textAlign: "left", cursor: "pointer", border: "none", background: "transparent" }}
                >
                    Second Tab
                </Tabs.Trigger>
                <Tabs.Trigger
                    value="tab3"
                    style={{ padding: "8px 16px", textAlign: "left", cursor: "pointer", border: "none", background: "transparent" }}
                >
                    Third Tab
                </Tabs.Trigger>
            </Tabs.List>
            <div style={{ flex: 1 }}>
                <Tabs.Content value="tab1">Content for the first tab.</Tabs.Content>
                <Tabs.Content value="tab2">Content for the second tab.</Tabs.Content>
                <Tabs.Content value="tab3">Content for the third tab.</Tabs.Content>
            </div>
        </Tabs>
    ),
};

export const ManualActivationTabs: Story = {
    render: () => (
        <Tabs defaultValue="1" activationMode="manual" style={{ width: 400, fontFamily: "sans-serif" }}>
            <p style={{ fontSize: "12px", color: "gray" }}>Use Arrow keys to focus, Space/Enter to activate.</p>
            <Tabs.List style={{ display: "flex", borderBottom: "1px solid #ccc", gap: 10, paddingBottom: 10 }}>
                <Tabs.Trigger
                    value="1"
                    style={{ padding: "8px 16px", cursor: "pointer", border: "none", background: "transparent" }}
                >
                    Tab 1
                </Tabs.Trigger>
                <Tabs.Trigger
                    value="2"
                    style={{ padding: "8px 16px", cursor: "pointer", border: "none", background: "transparent" }}
                >
                    Tab 2
                </Tabs.Trigger>
                <Tabs.Trigger
                    value="3"
                    style={{ padding: "8px 16px", cursor: "pointer", border: "none", background: "transparent" }}
                >
                    Tab 3
                </Tabs.Trigger>
            </Tabs.List>
            <div style={{ padding: "20px 0" }}>
                <Tabs.Content value="1">Tab 1 Content</Tabs.Content>
                <Tabs.Content value="2">Tab 2 Content</Tabs.Content>
                <Tabs.Content value="3">Tab 3 Content</Tabs.Content>
            </div>
        </Tabs>
    ),
};
